import type { InputHTMLAttributes, ReactNode } from 'react';
import type { TestComponentProps } from '../../types/test-component';
export interface RadioProps extends Omit<InputHTMLAttributes<HTMLInputElement>, 'type'>, TestComponentProps {
    /**
     * Заголовок
     */
    label?: string | ReactNode;
    /** Состояние радио "отмеченный"/ "неотмеченный" */
    checked?: boolean;
    /**
     * Состояние радио "заблокирован" / "разблокирован"
     */
    disabled?: boolean;
    /**
     * Признак ошибки. Применяет визуальные стили ошибки и устанавливает aria-invalid.
     */
    error?: boolean;
    /** Значение радио*/
    value?: string | number;
    /** Название группы радио*/
    name?: string;
}
